import { useEffect, useRef, type RefObject } from 'react';
import { scrollElementIntoView } from '@linm-soft-org/linm-web-common-components';

type ActiveInSection = (active: HTMLElement, sectionRoot: HTMLElement) => boolean;

/**
 * Scroll/focus dòng đang chọn — bỏ focus lần mount đầu để tránh viền focus-visible khi vừa load.
 */
export function useSelectedLineRowSync(
  rowRefs: RefObject<(HTMLTableRowElement | null)[]>,
  selectedLineIndex: number,
  options?: {
    sectionRef?: RefObject<HTMLElement | null>;
    isFieldTarget?: (target: HTMLElement) => boolean;
  },
): void {
  const skipRowFocusRef = useRef(true);

  useEffect(() => {
    const row = rowRefs.current?.[selectedLineIndex];
    const sectionRoot = options?.sectionRef?.current;
    const active = document.activeElement as HTMLElement | null;

    if (
      active
      && sectionRoot
      && options?.isFieldTarget?.(active)
      && sectionRoot.contains(active)
    ) {
      if (row) scrollElementIntoView(row, { block: 'nearest' });
      return;
    }

    if (skipRowFocusRef.current) {
      skipRowFocusRef.current = false;
      return;
    }

    row?.focus({ preventScroll: true });
    if (row) scrollElementIntoView(row, { block: 'nearest' });
  }, [options?.isFieldTarget, options?.sectionRef, rowRefs, selectedLineIndex]);
}
