import { useMemo } from 'react';
import {
  getFormFieldLock,
  type FormFieldLockInput,
  type FormFieldLockResult,
} from './FormMode';

/**
 * Hook bọc getFormFieldLock — dùng trên voucher / master full-page form.
 */
export function useFormFieldLock(input: FormFieldLockInput): FormFieldLockResult {
  const { formMode, isStatusLocked = false, styles } = input;

  return useMemo(
    () => getFormFieldLock({ formMode, isStatusLocked, styles }),
    [
      formMode,
      isStatusLocked,
      styles?.viewReadOnlySection,
      styles?.searchViewOnly,
      styles?.embeddedSearch,
      styles?.textareaReadOnly,
    ],
  );
}
